content.text:
Here is the completed, real-time cooperative **Email Sources Action Hub** featuring an elegant, high-profile Workspace design with a prominent header and exclusive focus on email communication sources.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Email Sources Action Hub</title>
  <!-- Tailwind CSS -->
  <script src="https://cdn.tailwindcss.com"></script>
  <!-- Google Fonts (Google Sans & Google Sans Text) -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;

      /* Material Design 3 tokens */
      --md-primary: #0b57d0;
      --md-on-primary: #ffffff;
      --md-primary-container: #d3e3fd;
      --md-surface: #ffffff;
      --md-surface-container: #f0f4f9;
      --md-outline: #747775;
    }
    body {
      font-family: 'Google Sans Text', sans-serif;
      background-color: var(--md-surface-container);
      color: #1f1f1f;
      margin: 0;
      padding: 0;
    }
    h1, h2, h3, h4, .google-sans {
      font-family: 'Google Sans', sans-serif;
    }
    .email-card.active {
      background-color: var(--md-primary-container);
      border-color: var(--md-primary);
    }
    /* Custom scrollbar to match Workspace design */
    ::-webkit-scrollbar {
      width: 8px;
      height: 8px;
    }
    ::-webkit-scrollbar-track {
      background: transparent;
    }
    ::-webkit-scrollbar-thumb {
      background: #c1c1c1;
      border-radius: 4px;
    }
    ::-webkit-scrollbar-thumb:hover {
      background: #a8a8a8;
    }
  </style>
</head>
<body class="min-h-screen bg-[#f0f4f9]">
  <div class="max-w-7xl mx-auto px-6 py-10">

    <!-- Polaris Large Header -->
    <header class="mb-8 border-b pb-6 border-slate-200">
      <div class="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 class="text-4xl font-bold tracking-tight text-gray-900 mb-2">Email Sources Action Hub</h1>
          <p class="text-sm text-gray-500 font-medium">Workspace Collaborative Intelligence & Task Synchronization</p>
        </div>

        <!-- Locked/Omitted Source indicator per system rules -->
        <div class="flex flex-wrap gap-2">
          <span class="inline-flex items-center gap-1.5 px-3.5 py-1.5 text-xs font-semibold rounded-full bg-blue-50 text-blue-700 border border-blue-200">
            <span class="w-2 h-2 rounded-full bg-blue-600 animate-pulse"></span>
            📧 Active: Email Sources Only
          </span>
          <span class="inline-flex items-center gap-1.5 px-3.5 py-1.5 text-xs font-medium rounded-full bg-gray-100 text-gray-400 border border-gray-200 cursor-not-allowed" title="Omitted per active configuration">
            📄 Docs: Locked (Omitted)
          </span>
          <span class="inline-flex items-center gap-1.5 px-3.5 py-1.5 text-xs font-medium rounded-full bg-gray-100 text-gray-400 border border-gray-200 cursor-not-allowed" title="Omitted per active configuration">
            💬 Chats: Locked (Omitted)
          </span>
        </div>
      </div>
    </header>

    <!-- Main Workspace Layout -->
    <div class="grid grid-cols-1 lg:grid-cols-12 gap-6">

      <!-- Left sidebar: Email list & Simulation -->
      <div class="lg:col-span-4 flex flex-col gap-6">

        <!-- Email Inbox List -->
        <div class="bg-white rounded-2xl border border-slate-200 p-4 shadow-sm flex flex-col h-[520px]">
          <div class="flex justify-between items-center mb-4">
            <h2 class="text-sm font-bold text-gray-800 uppercase tracking-wider">Inbox Email Sources</h2>
            <span id="unread-count" class="text-xs bg-blue-50 text-blue-700 border border-blue-100 px-2.5 py-0.5 rounded-full font-semibold">3 Emails</span>
          </div>

          <div id="email-list" class="flex-1 overflow-y-auto space-y-2 pr-1">
            <!-- Dynamically populated with active email cards -->
          </div>
        </div>

        <!-- Simulate Incoming Email Form -->
        <div class="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm">
          <h3 class="text-sm font-semibold text-gray-800 mb-3">Simulate Incoming Email</h3>
          <form id="email-compose-form" class="space-y-3">
            <div>
              <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Sender</label>
              <select id="compose-sender" class="w-full text-xs bg-slate-50 border border-slate-200 rounded-lg p-2.5 focus:outline-none focus:ring-1 focus:ring-blue-500 cursor-pointer">
                <!-- Dynamically populated with real team members -->
              </select>
            </div>
            <div>
              <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Subject</label>
              <input type="text" id="compose-subject" required placeholder="e.g., Action Required: Milestone alignment" class="w-full text-xs bg-slate-50 border border-slate-200 rounded-lg p-2.5 focus:outline-none focus:ring-1 focus:ring-blue-500">
            </div>
            <div>
              <label class="block text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Email Body</label>
              <textarea id="compose-body" required rows="3" placeholder="Write message body here. Include team member names to auto-extract tasks..." class="w-full text-xs bg-slate-50 border border-slate-200 rounded-lg p-2.5 focus:outline-none focus:ring-1 focus:ring-blue-500 resize-none"></textarea>
            </div>
            <button type="submit" class="w-full bg-blue-600 hover:bg-blue-700 text-white text-xs font-semibold py-2.5 px-3 rounded-lg transition duration-150">
              Receive Email
            </button>
          </form>
        </div>

      </div>

      <!-- Right panel: Active Email Details & Action Items -->
      <div class="lg:col-span-8 flex flex-col gap-6">

        <!-- Email Detail & Action Reader -->
        <div id="email-reader-card" class="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm flex flex-col min-h-[500px]">

          <div id="reader-empty" class="flex flex-col items-center justify-center flex-1 text-center py-12">
            <span class="text-5xl mb-4">📧</span>
            <p class="text-sm font-medium text-gray-500">Select an email source from the list to view and manage its action items</p>
          </div>

          <div id="reader-content" class="hidden flex-1 flex-col">

            <!-- Email Body Detail Header -->
            <div class="border-b border-slate-100 pb-5 mb-5">
              <div class="flex items-start justify-between gap-4">
                <div class="flex gap-3 items-center">
                  <img id="reader-avatar" src="" alt="" class="w-10 h-10 rounded-full border border-slate-100">
                  <div>
                    <h3 id="reader-subject" class="text-base font-bold text-gray-900 leading-snug"></h3>
                    <p class="text-xs text-gray-500 mt-0.5">
                      From: <span id="reader-sender-name" class="font-medium text-gray-700"></span> 
                      &lt;<span id="reader-sender-email"></span>&gt;
                    </p>
                  </div>
                </div>
                <span id="reader-date" class="text-xs text-gray-400 shrink-0"></span>
              </div>
              <div id="reader-body" class="text-sm text-gray-600 leading-relaxed mt-4 bg-slate-50 p-4 rounded-xl border border-slate-100 whitespace-pre-wrap"></div>
            </div>

            <!-- Action Items extracted from email -->
            <div class="flex-1 flex flex-col">
              <div class="flex justify-between items-center mb-3">
                <h4 class="text-sm font-semibold text-gray-800">Extracted Action Items</h4>
                <span id="action-stats" class="text-xs text-gray-500 font-medium"></span>
              </div>

              <div id="action-items-list" class="space-y-2 mb-4">
                <!-- Dynamically populated with actions -->
              </div>

              <!-- Add Action form -->
              <div class="border-t border-slate-100 pt-4 mt-auto">
                <form id="add-action-form" class="flex flex-wrap md:flex-nowrap gap-2 items-center">
                  <input type="text" id="new-action-text" required placeholder="Add new action item for this email..." class="flex-1 text-xs bg-slate-50 border border-slate-200 rounded-lg p-2.5 focus:outline-none focus:ring-1 focus:ring-blue-500">

                  <div class="flex items-center gap-1.5 bg-slate-50 border border-slate-200 rounded-lg px-2.5 py-1.5 shrink-0">
                    <span class="text-xs font-medium text-gray-500">Assignee:</span>
                    <select id="new-action-assignee" class="text-xs bg-transparent focus:outline-none font-semibold text-gray-700 py-0.5 cursor-pointer">
                      <!-- Dynamic list of team members -->
                    </select>
                  </div>

                  <button type="submit" class="bg-blue-600 hover:bg-blue-700 text-white text-xs font-semibold py-2.5 px-4 rounded-lg transition shrink-0">
                    Add Action
                  </button>
                </form>
              </div>

            </div>
          </div>

        </div>

      </div>

    </div>
  </div>

  <script>
    // Real Workspace Team Members
    const TEAM_MEMBERS = [
      { name: "Stephanie Goodson", email: "sgoodson@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXhSTeKdBDfDYWa6uS5J89rBh2uJHVV8OHoEUKYEe8AVFjY-4Q=s64" },
      { name: "David Wurtz", email: "wurtz@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW7KVh0yVuDb5C5TdRwGD7YYrY9iwTZzjNklnwKjpKGKeTFhayw=s64" },
      { name: "Chris Carroll", email: "cdcarroll@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVbB5SNQqui8-Dhh4ttI-p8lTdndJGcwTKlRrPnnNuKpJEXlKqF=s64" },
      { name: "Jannica Robertson", email: "jannicar@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWDycqL54QiGjUCQolQXjRQ80GsUFizqLOjmWN5j5IAy9-NLFIO=s64" },
      { name: "Frank Tisellano", email: "ftj@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWIXtfhCFx8S8zhFpLAaF9NZSiDJZmtDjpzW8DRqDnltb-otP9-=s64" },
      { name: "Megan Bruce", email: "meganbruce@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW14QaUGF52yVyOkgsoQgDd7YxKtA3flS0Y-FgQSpfMlPB5Cib_=s64" },
      { name: "Ajay Yadav", email: "yadavajay@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW5ytDzOzOxOMnVKGMTlZFIQFZGQE-F3hF9WT2C3_8rKFkSa6V4xQ=s64" },
      { name: "Belinda Preno", email: "belindapreno@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW8kkayF4FN3ib50ZpJsNFIMcSF9CLOgEcXNjlG9yhQ2xy1dL2q=s64" },
      { name: "Emily Thomas", email: "emilyjthomas@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVsXrPitMvyKTee1jfDjpODeKXAkN05NFP-MujtVh_GF6LFi1qw=s64" },
      { name: "Daniel Giuditta", email: "danielgiuditta@google.com", avatar: "https://lh3.googleusercontent.com/a/ACg8ocI4XtQJyOGEbExqDChL5Jutn2AfMdv-Yaq9Pbdd1NMuBb-qO08=s64" },
      { name: "Zhengrong Ji", email: "jizr@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWcXn2VmhyBKHwqviKOHkMtMPnIR1VFjOlNEyIMFrFI2C0Pt0Zj=s64" },
      { name: "Ryan Spohn", email: "rspohn@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVbqXCvGLcBpDuCdv05JUnymeuoDYoUYTELHxdY4k_5BhnH6GWHMg=s64" },
      { name: "Laurence Fahey", email: "laurencefahey@google.com", avatar: "https://lh3.googleusercontent.com/a/ACg8ocLLL2cXiri5iV3mBRXg2mYrij2OJg28l3nTJrtWU5YQlotT2iUH=s64" },
      { name: "Ian Mendiola", email: "ianmendiola@google.com", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUP0nZZSsC7tRQg_3si0rRn-TJyMoD8j0kfQm3I-HdLEIVQYBsG=s64" }
    ];

    // Initial default mock email dataset
    const initialEmails = [
      {
        id: "mail-1",
        sender: {
          name: "Stephanie Goodson",
          email: "sgoodson@google.com",
          avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXhSTeKdBDfDYWa6uS5J89rBh2uJHVV8OHoEUKYEe8AVFjY-4Q=s64"
        },
        subject: "Q3 Workspace Strategy Alignment Deck",
        date: "Today, 10:24 AM",
        body: "Hi team, we need to finalize the Q3 alignment deck by Friday. David, can you pull the user growth metrics? Chris, please update the engineering milestone roadmap. Let's sync on Wednesday.",
        actions: [
          { id: "act-1", text: "Pull Q3 user growth metrics", assigneeEmail: "wurtz@google.com", completed: false },
          { id: "act-2", text: "Update engineering milestone roadmap", assigneeEmail: "cdcarroll@google.com", completed: false }
        ]
      },
      {
        id: "mail-2",
        sender: {
          name: "Frank Tisellano",
          email: "ftj@google.com",
          avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWIXtfhCFx8S8zhFpLAaF9NZSiDJZmtDjpzW8DRqDnltb-otP9-=s64"
        },
        subject: "Design Review: Polaris Spacing Integrity",
        date: "Today, 9:15 AM",
        body: "I reviewed the new dashboard layout. The spacing variables are correct, but let's make sure the header is extremely prominent (make it bigger!). Jannica, please double-check the typography size tokens to fit this style.",
        actions: [
          { id: "act-3", text: "Verify typography size tokens on dashboard", assigneeEmail: "jannicar@google.com", completed: false }
        ]
      },
      {
        id: "mail-3",
        sender: {
          name: "Megan Bruce",
          email: "meganbruce@google.com",
          avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW14QaUGF52yVyOkgsoQgDd7YxKtA3flS0Y-FgQSpfMlPB5Cib_=s64"
        },
        subject: "Customer Feedback Report & Actions",
        date: "Yesterday",
        body: "The feedback from our key enterprise partners looks solid. However, they reported slow load times on heavy data tables. Ryan, let's run performance profiling on the data loader. Emily, we should update the partner status report.",
        actions: [
          { id: "act-4", text: "Profile performance on heavy data tables", assigneeEmail: "rspohn@google.com", completed: true },
          { id: "act-5", text: "Update enterprise partner status report", assigneeEmail: "emilyjthomas@google.com", completed: false }
        ]
      }
    ];

    const envId = window.__sandboxEnvId;
    const syncKey = "email_hub_action_state_v3";

    let emails = [...initialEmails];
    let selectedEmailId = "mail-1";

    // Team Lookup Utility
    function getMember(email) {
      return TEAM_MEMBERS.find(m => m.email === email) || { name: email, email: email, avatar: "" };
    }

    // Populate team dropdown lists
    function populateTeamDropdowns() {
      const composeSelect = document.getElementById("compose-sender");
      const assigneeSelect = document.getElementById("new-action-assignee");

      composeSelect.innerHTML = "";
      assigneeSelect.innerHTML = "";

      TEAM_MEMBERS.forEach(member => {
        const opt1 = document.createElement("option");
        opt1.value = member.email;
        opt1.innerText = `${member.name} (${member.email.split('@')[0]})`;
        composeSelect.appendChild(opt1);

        const opt2 = document.createElement("option");
        opt2.value = member.email;
        opt2.innerText = member.name;
        assigneeSelect.appendChild(opt2);
      });
    }

    // Render Email Sidebar Cards
    function renderEmailList() {
      const container = document.getElementById("email-list");
      container.innerHTML = "";

      emails.forEach(mail => {
        const isSelected = selectedEmailId === mail.id;
        const card = document.createElement("div");
        card.className = `email-card p-3 rounded-xl border transition cursor-pointer flex flex-col gap-1.5 ${
          isSelected 
            ? "bg-blue-50 border-blue-200" 
            : "bg-white border-slate-100 hover:border-slate-300"
        }`;

        card.onclick = () => {
          selectedEmailId = mail.id;
          renderEmailList();
          renderEmailReader();
        };

        const pendingTasks = mail.actions.filter(a => !a.completed).length;
        const totalTasks = mail.actions.length;

        card.innerHTML = `
          <div class="flex justify-between items-start gap-2">
            <div class="flex items-center gap-2">
              <img src="${mail.sender.avatar}" alt="" class="w-6 h-6 rounded-full border border-slate-100">
              <span class="text-xs font-bold text-gray-800 truncate max-w-[130px]">${mail.sender.name}</span>
            </div>
            <span class="text-[10px] text-gray-400 shrink-0">${mail.date}</span>
          </div>
          <div class="text-xs font-semibold text-gray-900 truncate">${mail.subject}</div>
          <div class="text-[11px] text-gray-500 line-clamp-1">${mail.body}</div>
          <div class="flex items-center justify-between mt-1 text-[10px] text-gray-400">
            <span class="flex items-center gap-1">
              📧 Email Source
            </span>
            ${totalTasks > 0 ? `
              <span class="font-semibold ${pendingTasks > 0 ? "text-blue-600" : "text-emerald-600"}">
                ${pendingTasks} of ${totalTasks} pending
              </span>
            ` : `<span class="text-gray-300">No actions</span>`}
          </div>
        `;
        container.appendChild(card);
      });

      document.getElementById("unread-count").innerText = `${emails.length} Email${emails.length !== 1 ? 's' : ''}`;
    }

    // Render Expanded Active Email Details and Actions
    function renderEmailReader() {
      const empty = document.getElementById("reader-empty");
      const content = document.getElementById("reader-content");

      const mail = emails.find(m => m.id === selectedEmailId);
      if (!mail) {
        empty.classList.remove("hidden");
        content.classList.add("hidden");
        return;
      }

      empty.classList.add("hidden");
      content.classList.remove("hidden");

      document.getElementById("reader-avatar").src = mail.sender.avatar;
      document.getElementById("reader-subject").innerText = mail.subject;
      document.getElementById("reader-sender-name").innerText = mail.sender.name;
      document.getElementById("reader-sender-email").innerText = mail.sender.email;
      document.getElementById("reader-date").innerText = mail.date;
      document.getElementById("reader-body").innerText = mail.body;

      const actionsList = document.getElementById("action-items-list");
      actionsList.innerHTML = "";

      const pendingCount = mail.actions.filter(a => !a.completed).length;
      document.getElementById("action-stats").innerText = `${pendingCount} item${pendingCount !== 1 ? 's' : ''} pending`;

      if (mail.actions.length === 0) {
        actionsList.innerHTML = `
          <div class="text-center py-6 border border-dashed border-slate-200 rounded-xl bg-slate-50">
            <p class="text-xs text-gray-400 font-medium">No action items assigned to this email yet.</p>
          </div>
        `;
      } else {
        mail.actions.forEach(action => {
          const member = getMember(action.assigneeEmail);
          const actionRow = document.createElement("div");
          actionRow.className = `flex items-center justify-between p-3 rounded-xl border border-slate-100 ${
            action.completed ? "bg-slate-50 opacity-75" : "bg-white shadow-sm animate-fade-in"
          }`;

          actionRow.innerHTML = `
            <div class="flex items-center gap-3 flex-1 min-w-0">
              <input type="checkbox" ${action.completed ? "checked" : ""} class="w-4 h-4 rounded text-blue-600 border-slate-300 focus:ring-blue-500 cursor-pointer" onclick="toggleAction('${mail.id}', '${action.id}')">
              <span class="text-xs font-medium text-gray-800 ${action.completed ? "line-through text-gray-400" : ""} truncate">${action.text}</span>
            </div>
            <div class="flex items-center gap-3">
              <div class="flex items-center gap-1.5 bg-slate-50 border border-slate-200 rounded-full pl-1.5 pr-2.5 py-0.5">
