    // Add Action Submit Handler
    document.getElementById("add-action-form").onsubmit = function(e) {
      e.preventDefault();
      const mail = emails.find(m => m.id === selectedEmailId);
      if (!mail) return;

      const textInput = document.getElementById("new-action-text");
      const assigneeSelect = document.getElementById("new-action-assignee");

