    // Receive Simulated Email Form Handler (Automatic task extraction)
    document.getElementById("email-compose-form").onsubmit = function(e) {
      e.preventDefault();
      const senderEmail = document.getElementById("compose-sender").value;
      const subject = document.getElementById("compose-subject").value.trim();
      const body = document.getElementById("compose-body").value.trim();

      const sender = TEAM_MEMBERS.find(m => m.email === senderEmail);
      if (!sender) return;

      const newEmail = {
        id: "mail-" + Date.now(),
        sender: {
          name: sender.name,
          email: sender.email,
          avatar: sender.avatar
        },
        subject: subject,
        date: "Just Now",
        body: body,
        actions: []
      };

      // Smart Auto-Extractor: If the email body mentions team member names, extract the requested items!
      TEAM_MEMBERS.forEach(member => {
        const firstName = member.name.split(" ")[0];
        const regex = new RegExp(`(${firstName}|${member.name})[^.?!]*,?\\s*(?:please|can you|to|should)\\s+([^.?!]+)`, "i");
        const match = body.match(regex);
        if (match) {
          let extractedText = match[0].trim();
          // Capitalize first letter of extraction
          extractedText = extractedText.charAt(0).toUpperCase() + extractedText.slice(1);
          newEmail.actions.push({
            id: "act-" + Date.now() + "-" + Math.random().toString(36).substr(2, 4),
            text: extractedText,
            assigneeEmail: member.email,
            completed: false
          });
        }
      });

      emails.unshift(newEmail);
      selectedEmailId = newEmail.id;

      saveSyncedState(emails);

      document.getElementById("compose-subject").value = "";
      document.getElementById("compose-body").value = "";

      renderEmailList();
      renderEmailReader();
