    // Sync state fetch controllers
    async function loadSyncedState() {
      if (!envId) {
        const local = localStorage.getItem(syncKey);
        if (local) {
          const parsed = JSON.parse(local);
          if (JSON.stringify(emails) !== JSON.stringify(parsed)) {
            emails = parsed;
            if (!emails.find(m => m.id === selectedEmailId)) {
              selectedEmailId = emails[0]?.id || null;
            }
            renderEmailList();
            renderEmailReader();
          }
        }
        return;
      }

      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data) {
          const serverState = json.data;
          // Only overwrite and re-render if data has changed to prevent active element flicker
          if (JSON.stringify(emails) !== JSON.stringify(serverState)) {
            emails = serverState;
            if (!emails.find(m => m.id === selectedEmailId)) {
              selectedEmailId = emails[0]?.id || null;
            }
            renderEmailList();
            renderEmailReader();
          }
        } else {
          await saveSyncedState(initialEmails);
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    async function saveSyncedState(newState) {
      if (!envId) {
        localStorage.setItem(syncKey, JSON.stringify(newState));
        return;
      }
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    // App Initialization
    window.addEventListener("DOMContentLoaded", () => {
      populateTeamDropdowns();
      renderEmailList();
      renderEmailReader();

      loadSyncedState();

      // Short poll every 2 seconds for flawless multi-user sync
      setInterval(loadSyncedState, 2000);
    });
